PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE suppliers (
    id               INTEGER PRIMARY KEY AUTOINCREMENT,
    name             TEXT    NOT NULL,
    trade_name       TEXT,
    vat_number       TEXT    UNIQUE,
    phone            TEXT,
    email            TEXT,
    address          TEXT,
    payment_terms    TEXT,
    is_active        INTEGER NOT NULL DEFAULT 1,   -- 1 = true
    created_at       TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE product_categories (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    name        TEXT    NOT NULL,
    parent_id   INTEGER REFERENCES product_categories(id),
    created_at  TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE units_of_measure (
    id                INTEGER PRIMARY KEY AUTOINCREMENT,
    name              TEXT    NOT NULL,
    abbreviation      TEXT    NOT NULL,
    base_unit_id      INTEGER REFERENCES units_of_measure(id),
    conversion_factor REAL                           -- e.g. 6 means 1 of this = 6 of base
);
CREATE TABLE supplier_products (
    id                     INTEGER PRIMARY KEY AUTOINCREMENT,
    supplier_id            INTEGER NOT NULL REFERENCES suppliers(id),
    product_id             INTEGER NOT NULL REFERENCES products(id),
    supplier_sku           TEXT,                     -- code as printed on invoice
    supplier_product_name  TEXT,                     -- name as printed on invoice
    current_price          REAL,                     -- latest net unit price (pre-tax)
    is_preferred_supplier  INTEGER NOT NULL DEFAULT 0,
    lead_time_days         INTEGER,
    min_order_qty          REAL,
    is_active              INTEGER NOT NULL DEFAULT 1,
    updated_at             TEXT    NOT NULL DEFAULT (datetime('now')), total_quantity_ordered REAL DEFAULT 0,
    UNIQUE (supplier_id, supplier_sku)
);
CREATE TABLE invoice_lines (
    id                    INTEGER PRIMARY KEY AUTOINCREMENT,
    invoice_id            INTEGER NOT NULL REFERENCES invoices(id),
    supplier_product_id   INTEGER REFERENCES supplier_products(id),
    line_description      TEXT,                      -- fallback if product not yet in catalogue
    quantity              REAL    NOT NULL,
    unit_id               INTEGER REFERENCES units_of_measure(id),
    unit_price            REAL    NOT NULL,           -- net, pre-tax, at time of invoice
    discount_percent      REAL    NOT NULL DEFAULT 0,
    line_net_amount       REAL    NOT NULL,
    vat_rate              REAL    NOT NULL DEFAULT 0,
    excise_duty_per_unit  REAL    NOT NULL DEFAULT 0,
    line_gross_amount     REAL    NOT NULL
);
CREATE TABLE price_history (
    id                    INTEGER PRIMARY KEY AUTOINCREMENT,
    supplier_product_id   INTEGER NOT NULL REFERENCES supplier_products(id),
    unit_price            REAL    NOT NULL,
    vat_rate              REAL    NOT NULL DEFAULT 0,
    excise_duty_per_unit  REAL    NOT NULL DEFAULT 0,
    effective_from        TEXT    NOT NULL,           -- ISO-8601 date
    invoice_id            INTEGER REFERENCES invoices(id),
    created_at            TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE schema_migrations (
            version    INTEGER PRIMARY KEY,
            name       TEXT    NOT NULL,
            applied_at TEXT    NOT NULL DEFAULT (datetime('now'))
        );
CREATE TABLE stock_locations (
    id         INTEGER PRIMARY KEY AUTOINCREMENT,
    name       TEXT    NOT NULL UNIQUE,
    sort_order INTEGER NOT NULL DEFAULT 0,
    is_active  INTEGER NOT NULL DEFAULT 1
);
CREATE TABLE inventory_balances (
    id           INTEGER PRIMARY KEY AUTOINCREMENT,
    product_id   INTEGER NOT NULL REFERENCES products(id),
    location_id  INTEGER NOT NULL REFERENCES stock_locations(id),
    quantity     REAL    NOT NULL DEFAULT 0,
    unit_id      INTEGER REFERENCES units_of_measure(id),
    last_updated TEXT    NOT NULL DEFAULT (datetime('now')),
    UNIQUE (product_id, location_id)
);
CREATE TABLE waste_events (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    product_id  INTEGER NOT NULL REFERENCES products(id),
    location_id INTEGER NOT NULL REFERENCES stock_locations(id),
    quantity    REAL    NOT NULL,
    unit_id     INTEGER REFERENCES units_of_measure(id),
    reason      TEXT    CHECK (reason IN (
                    'expired', 'broken', 'spoiled', 'overproduction', 'other'
                )),
    waste_date  TEXT    NOT NULL DEFAULT (date('now')),
    notes       TEXT,
    created_at  TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE IF NOT EXISTS "composite_product_components" (
    id                     INTEGER PRIMARY KEY AUTOINCREMENT,
    composite_product_id   INTEGER NOT NULL
                            REFERENCES "composite_products"(id) ON DELETE CASCADE,
    component_product_id   INTEGER REFERENCES products(id),
    component_composite_id INTEGER REFERENCES "composite_products"(id),
    quantity               REAL    NOT NULL,
    unit                   TEXT
);
CREATE TABLE unit_conversions (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    from_unit_id INTEGER NOT NULL REFERENCES units_of_measure(id),
    to_unit_id   INTEGER NOT NULL REFERENCES units_of_measure(id),
    factor       REAL    NOT NULL,
    product_id   INTEGER REFERENCES products(id),  -- NULL = global conversion
    UNIQUE (from_unit_id, to_unit_id, product_id)
);
CREATE TABLE production_batches (
    id                   INTEGER PRIMARY KEY AUTOINCREMENT,
    composite_product_id INTEGER NOT NULL REFERENCES composite_products(id),
    location_id          INTEGER NOT NULL REFERENCES stock_locations(id),
    batch_size           REAL    NOT NULL DEFAULT 1,
    produced_at          TEXT    NOT NULL DEFAULT (datetime('now')),
    notes                TEXT,
    status               TEXT    NOT NULL DEFAULT 'draft'
                         CHECK (status IN ('draft', 'committed'))
);
CREATE TABLE recipe_yields (
    id                   INTEGER PRIMARY KEY AUTOINCREMENT,
    composite_product_id INTEGER NOT NULL REFERENCES composite_products(id) ON DELETE CASCADE,
    yield_product_id     INTEGER REFERENCES products(id),
    yield_composite_id   INTEGER REFERENCES composite_products(id),
    yield_quantity       REAL    NOT NULL,
    unit_id              INTEGER REFERENCES units_of_measure(id)
);
CREATE TABLE recipe_cost_snapshots (
    id                   INTEGER PRIMARY KEY AUTOINCREMENT,
    production_batch_id  INTEGER NOT NULL REFERENCES production_batches(id) ON DELETE CASCADE,
    composite_product_id INTEGER NOT NULL REFERENCES composite_products(id),
    total_food_cost      REAL    NOT NULL,
    cost_per_serving     REAL    NOT NULL,
    snapped_at           TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE IF NOT EXISTS "products" (
    id                INTEGER PRIMARY KEY AUTOINCREMENT,
    name              TEXT    NOT NULL,
    description       TEXT,
    category_id       INTEGER REFERENCES product_categories(id),
    unit_id           INTEGER REFERENCES units_of_measure(id),
    volume_ml         INTEGER,
    abv_percent       REAL,
    units_per_pack    REAL,
    pack_unit_id      INTEGER REFERENCES units_of_measure(id),
    pack_unit_size_ml REAL,
    barcode           TEXT,
    is_active         INTEGER NOT NULL DEFAULT 1,
    min_stock_level   REAL,
    created_at        TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE stock_count_sessions (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    location_id INTEGER NOT NULL REFERENCES stock_locations(id),
    counted_at  TEXT    NOT NULL DEFAULT (datetime('now')),
    frozen_at   TEXT,
    notes       TEXT,
    status      TEXT    NOT NULL DEFAULT 'draft'
                CHECK (status IN ('draft', 'pending_approval', 'committed'))
);
CREATE TABLE stock_count_lines (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id  INTEGER NOT NULL REFERENCES stock_count_sessions(id) ON DELETE CASCADE,
    product_id  INTEGER NOT NULL REFERENCES products(id),
    counted_qty REAL,
    system_qty  REAL,
    unit_id     INTEGER REFERENCES units_of_measure(id),
    notes       TEXT,
    UNIQUE (session_id, product_id)
);
CREATE TABLE IF NOT EXISTS "stock_movements" (
    id             INTEGER PRIMARY KEY AUTOINCREMENT,
    product_id     INTEGER NOT NULL REFERENCES products(id),
    location_id    INTEGER NOT NULL REFERENCES stock_locations(id),
    movement_type  TEXT    NOT NULL
                   CHECK (movement_type IN (
                       'purchase_receipt',
                       'adjustment_up',
                       'adjustment_down',
                       'waste',
                       'transfer_out',
                       'transfer_in',
                       'production_consumption',
                       'production_output',
                       'count_reconciliation',
                       'opening'
                   )),
    quantity       REAL    NOT NULL,
    unit_id        INTEGER REFERENCES units_of_measure(id),
    reason         TEXT,
    reference_id   INTEGER,
    reference_type TEXT,
    notes          TEXT,
    moved_at       TEXT    NOT NULL DEFAULT (datetime('now')),
    created_at     TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE stock_transfers (
    id               INTEGER PRIMARY KEY AUTOINCREMENT,
    from_location_id INTEGER NOT NULL REFERENCES stock_locations(id),
    to_location_id   INTEGER NOT NULL REFERENCES stock_locations(id),
    status           TEXT    NOT NULL DEFAULT 'draft',
    notes            TEXT,
    created_at       TEXT    NOT NULL DEFAULT (datetime('now')),
    confirmed_at     TEXT,
    cancelled_at     TEXT
);
CREATE TABLE stock_transfer_lines (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    transfer_id INTEGER NOT NULL REFERENCES stock_transfers(id) ON DELETE CASCADE,
    product_id  INTEGER NOT NULL REFERENCES products(id),
    quantity    REAL    NOT NULL,
    unit_id     INTEGER REFERENCES units_of_measure(id),
    notes       TEXT
);
CREATE TABLE IF NOT EXISTS "invoices" (
    id                   INTEGER PRIMARY KEY AUTOINCREMENT,
    supplier_id          INTEGER NOT NULL REFERENCES suppliers(id),
    invoice_number       TEXT    NOT NULL,
    invoice_date         TEXT    NOT NULL,
    delivery_date        TEXT,
    net_amount           REAL    NOT NULL DEFAULT 0,
    vat_amount           REAL    NOT NULL DEFAULT 0,
    excise_duty_amount   REAL    NOT NULL DEFAULT 0,
    gross_amount         REAL    NOT NULL DEFAULT 0,
    currency             TEXT    NOT NULL DEFAULT 'EUR',
    status               TEXT    NOT NULL DEFAULT 'received'
                             CHECK (status IN ('received','verified','posted','disputed')),
    notes                TEXT,
    pdf_path             TEXT,
    created_at           TEXT    NOT NULL DEFAULT (datetime('now')),
    UNIQUE (supplier_id, invoice_number)
);
CREATE TABLE IF NOT EXISTS "composite_products" (
    id                      INTEGER PRIMARY KEY AUTOINCREMENT,
    name                    TEXT    NOT NULL,
    category                TEXT,
    selling_price           REAL,
    selling_price_takeaway  REAL,
    selling_price_delivery  REAL,
    servings                INTEGER NOT NULL DEFAULT 1,
    yield_quantity          REAL,
    yield_unit              TEXT,
    prep_time_minutes       INTEGER,
    notes                   TEXT,
    product_type            TEXT    NOT NULL DEFAULT 'composite'
                            CHECK (product_type IN ('composite', 'intermediate')),
    is_archived             INTEGER NOT NULL DEFAULT 0,
    created_at              TEXT    NOT NULL DEFAULT (datetime('now'))
);
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_stock_movements_product
    ON stock_movements (product_id, location_id);
CREATE INDEX idx_stock_transfers_status        ON stock_transfers(status);
CREATE INDEX idx_stock_transfers_from_loc      ON stock_transfers(from_location_id);
CREATE INDEX idx_stock_transfers_to_loc        ON stock_transfers(to_location_id);
CREATE INDEX idx_stock_transfer_lines_transfer ON stock_transfer_lines(transfer_id);
PRAGMA writable_schema=OFF;
COMMIT;
